module binary_to_gray (
  input clk,
  input [3:0] binary_input,
  output [3:0] gray_output
);

  reg [3:0] inv_gray_reg;

  always@(posedge clk) begin
    inv_gray_reg[3] <= binary_input[3];
    inv_gray_reg[2] <= binary_input[3] ^ binary_input[2];
    inv_gray_reg[1] <= binary_input[2] ^ binary_input[1];
    inv_gray_reg[0] <= binary_input[1] ^ binary_input[0];
  end

  assign gray_output = inv_gray_reg;

endmodule
